504 /// Build up the general order of nodes, by performing a topological sort of the
505 /// parent region's nodes, while ensuring that there is no outer cycle node
506 /// between any two inner cycle nodes.
507 void StructurizeCFG::orderNodes() {
508   Order.resize(std::distance(GraphTraits<Region *>::nodes_begin(ParentRegion),
509                              GraphTraits<Region *>::nodes_end(ParentRegion)));
510   if (Order.empty())
511     return;
512 
513   SmallDenseSet<RegionNode *> Nodes;
514   auto EntryNode = SubGraphTraits::getEntryNode(ParentRegion);
515 
516   // A list of range indices of SCCs in Order, to be processed.
517   SmallVector<std::pair<unsigned, unsigned>, 8> WorkList;
518   unsigned I = 0, E = Order.size();
519   while (true) {
520     // Run through all the SCCs in the subgraph starting with Entry.
521     for (auto SCCI =
522              scc_iterator<SubGraphTraits::NodeRef, SubGraphTraits>::begin(
523                  EntryNode);
524          !SCCI.isAtEnd(); ++SCCI) {
525       auto &SCC = *SCCI;
526 
527       // An SCC up to the size of 2, can be reduced to an entry (the last node),
528       // and a possible additional node. Therefore, it is already in order, and
529       // there is no need to add it to the work-list.
530       unsigned Size = SCC.size();
531       if (Size > 2)
532         WorkList.emplace_back(I, I + Size);
533 
534       // Add the SCC nodes to the Order array.
535       for (const auto &N : SCC) {
536         assert(I < E && "SCC size mismatch!");
537         Order[I++] = N.first;
538       }
539     }
540     assert(I == E && "SCC size mismatch!");
541 
542     // If there are no more SCCs to order, then we are done.
543     if (WorkList.empty())
544       break;
545 
546     std::tie(I, E) = WorkList.pop_back_val();
547 
548     // Collect the set of nodes in the SCC's subgraph. These are only the
549     // possible child nodes; we do not add the entry (last node) otherwise we
550     // will have the same exact SCC all over again.
551     Nodes.clear();
552     Nodes.insert(Order.begin() + I, Order.begin() + E - 1);
553 
554     // Update the entry node.
555     EntryNode.first = Order[E - 1];
556     EntryNode.second = &Nodes;
557   }
558 }
