598 void StructurizeCFG::gatherPredicates(RegionNode *N) {
599   RegionInfo *RI = ParentRegion->getRegionInfo();
600   BasicBlock *BB = N->getEntry();
601   BBPredicates &Pred = Predicates[BB];
602   BBPredicates &LPred = LoopPreds[BB];
603 
604   for (BasicBlock *P : predecessors(BB)) {
605     // Ignore it if it's a branch from outside into our region entry
606     if (!ParentRegion->contains(P) || !dyn_cast<BranchInst>(P->getTerminator()))
607       continue;
608 
609     Region *R = RI->getRegionFor(P);
610     if (R == ParentRegion) {
611       // It's a top level block in our region
612       BranchInst *Term = cast<BranchInst>(P->getTerminator());
613       for (unsigned i = 0, e = Term->getNumSuccessors(); i != e; ++i) {
614         BasicBlock *Succ = Term->getSuccessor(i);
615         if (Succ != BB)
616           continue;
617 
618         if (Visited.count(P)) {
619           // Normal forward edge
620           if (Term->isConditional()) {
621             // Try to treat it like an ELSE block
622             BasicBlock *Other = Term->getSuccessor(!i);
623             if (Visited.count(Other) && !Loops.count(Other) &&
624                 !Pred.count(Other) && !Pred.count(P)) {
625               hoistZeroCostElseBlockPhiValues(Succ, Other);
626               Pred[Other] = {BoolFalse, std::nullopt};
627               Pred[P] = {BoolTrue, std::nullopt};
628               continue;
629             }
630           }
631           Pred[P] = buildCondition(Term, i, false);
632         } else {
633           // Back edge
634           LPred[P] = buildCondition(Term, i, true);
635         }
636       }
637     } else {
638       // It's an exit from a sub region
639       while (R->getParent() != ParentRegion)
640         R = R->getParent();
641 
642       // Edge from inside a subregion to its entry, ignore it
643       if (*R == *N)
644         continue;
645 
646       BasicBlock *Entry = R->getEntry();
647       if (Visited.count(Entry))
648         Pred[Entry] = {BoolTrue, std::nullopt};
649       else
650         LPred[Entry] = {BoolFalse, std::nullopt};
651     }
652   }
