1055 /// Let node exit(s) point to NewExit
1056 void StructurizeCFG::changeExit(RegionNode *Node, BasicBlock *NewExit,
1057                                 bool IncludeDominator) {
1058   if (Node->isSubRegion()) {
1059     Region *SubRegion = Node->getNodeAs<Region>();
1060     BasicBlock *OldExit = SubRegion->getExit();
1061     BasicBlock *Dominator = nullptr;
1062 
1063     // Find all the edges from the sub region to the exit.
1064     // We use make_early_inc_range here because we modify BB's terminator.
1065     for (BasicBlock *BB : llvm::make_early_inc_range(predecessors(OldExit))) {
1066       if (!SubRegion->contains(BB))
1067         continue;
1068 
1069       // Modify the edges to point to the new exit
1070       delPhiValues(BB, OldExit);
1071       BB->getTerminator()->replaceUsesOfWith(OldExit, NewExit);
1072       addPhiValues(BB, NewExit);
1073 
1074       // Find the new dominator (if requested)
1075       if (IncludeDominator) {
1076         if (!Dominator)
1077           Dominator = BB;
1078         else
1079           Dominator = DT->findNearestCommonDominator(Dominator, BB);
1080       }
1081     }
1082 
1083     // Change the dominator (if requested)
1084     if (Dominator)
1085       DT->changeImmediateDominator(NewExit, Dominator);
1086 
1087     // Update the region info
1088     SubRegion->replaceExit(NewExit);
1089   } else {
1090     BasicBlock *BB = Node->getNodeAs<BasicBlock>();
1091     DebugLoc DL = killTerminator(BB);
1092     BranchInst *Br = BranchInst::Create(NewExit, BB);
1093     Br->setDebugLoc(DL);
1094     addPhiValues(BB, NewExit);
1095     if (IncludeDominator)
1096       DT->changeImmediateDominator(NewExit, BB);
1097   }
1098 }
